// Read entire contents of an open file handle into a heap buffer, chunking
// reads so files larger than ReadFile's DWORD size limit (~2GB) work.
// Returns nullptr on allocation or read failure. Buffer is null-terminated
// (one extra byte) and owned by the caller.
static char* read_handle_chunked(HANDLE file, size_t size) {
    char* buf = new (std::nothrow) char[size + 1];
    if (!buf) return nullptr;

    constexpr DWORD MAX_CHUNK = 0x7FFFFFFFu;
    size_t total_read = 0;
    while (total_read < size) {
        DWORD chunk = static_cast<DWORD>(
            (size - total_read) > MAX_CHUNK ? MAX_CHUNK : (size - total_read));
        DWORD bytes_read = 0;
        if (!ReadFile(file, buf + total_read, chunk, &bytes_read, nullptr) ||
            bytes_read != chunk) {
            delete[] buf;
            return nullptr;
        }
        total_read += bytes_read;
    }
    buf[size] = '\0';
    return buf;
}

