// Open and parse the git index file (.git/index)
bool git_index_open(GitRepository* repo, GitIndex* index) {
    if (!repo || !repo->is_valid || !index) return false;

    memset(index, 0, sizeof(GitIndex));

    // Build path to index file
    wchar_t index_path[Git::MAX_PATH_LEN];
    wchar_t git_dir_wide[Git::MAX_PATH_LEN];
    utf8_to_wide_n(repo->git_dir, git_dir_wide, Git::MAX_PATH_LEN);
    make_path(index_path, Git::MAX_PATH_LEN, git_dir_wide, L"index");

    // Memory-map the index file
    MemoryMap* mmap = mmap_open(index_path);
    if (!mmap || !mmap->data || mmap->size < 32) {  // 12 header + 20 trailer minimum
        mmap_close(mmap);
        return false;
    }

    const uint8_t* data = static_cast<const uint8_t*>(mmap->data);

    // Validate SHA-1 trailer: last 20 bytes are SHA-1 of all preceding bytes
    {
        uint8_t actual_sha[20];
        sha1_compute(data, mmap->size - 20, actual_sha);
        if (memcmp(actual_sha, data + mmap->size - 20, 20) != 0) {
            LOG("git_index_open: SHA-1 trailer mismatch - index file may be corrupt");
            mmap_close(mmap);
            return false;
        }
    }

    // Validate header: "DIRC" signature
    uint32_t signature = read_be32(data);
    if (signature != Git::INDEX_SIGNATURE) {
        mmap_close(mmap);
        return false;
    }

    // Read version and entry count
    index->version = read_be32(data + 4);
    uint32_t entry_count = read_be32(data + 8);

    // Only support v2 and v3 (v4 has path compression)
    if (index->version < 2 || index->version > 3) {
        mmap_close(mmap);
        return false;
    }

    // Validate entry_count against file size to reject corrupt/malicious indexes.
    // Minimum on-disk entry size is 64 bytes (62 fixed header + 1 path byte + 1 null).
    // Reject counts that can't possibly fit in the mapped data.
    constexpr size_t MIN_ENTRY_BYTES = 64;
    if (entry_count > mmap->size / MIN_ENTRY_BYTES) {
        mmap_close(mmap);
        return false;
    }

    // Allocate entries (entry_count is now bounded by mmap->size / MIN_ENTRY_BYTES)
    index->entries = new (std::nothrow) GitIndexEntry[entry_count];
    if (!index->entries) {
        mmap_close(mmap);
        return false;
    }
    index->entry_count = 0;

    // Parse entries
    const uint8_t* ptr = data + 12;  // After header
    const uint8_t* end = data + mmap->size;
    uint32_t processed = 0;
    bool truncated = false;

    for (uint32_t i = 0; i < entry_count && ptr < end; i++) {
        // Entry format (v2/v3):
        // 32-bit ctime seconds
        // 32-bit ctime nanoseconds
        // 32-bit mtime seconds
        // 32-bit mtime nanoseconds
        // 32-bit dev
        // 32-bit ino
        // 32-bit mode
        // 32-bit uid
        // 32-bit gid
        // 32-bit file size
        // 20-byte SHA-1
        // 16-bit flags (12-bit name length, 1-bit extended, 2-bit stage, 1-bit assume-valid)
        // [16-bit extended flags if extended flag set in flags (v3)]
        // Variable-length path (null-terminated)
        // Padding to 8-byte boundary (from entry start)

        if (ptr + 62 > end) { truncated = true; break; }

        const uint8_t* entry_start = ptr;

        // Skip ctime(8), mtime(8), dev(4), ino(4) = 24 bytes
        ptr += 24;

        // Read mode
        uint32_t mode = read_be32(ptr);
        ptr += 4;

        // Skip uid, gid, size (12 bytes)
        ptr += 12;

        // Read SHA (20 bytes)
        char sha[Git::SHA1_HEX_SIZE + 1];
        sha1_to_hex(ptr, sha);
        ptr += 20;

        // Read flags
        uint16_t flags = (ptr[0] << 8) | ptr[1];
        ptr += 2;
        uint8_t stage = static_cast<uint8_t>((flags >> 12) & 0x3);

        // Extended flags (v3 only)
        if (index->version >= 3 && (flags & 0x4000)) {
            if (ptr + 2 > end) { truncated = true; break; }
            ptr += 2;  // Skip extended flags
        }

        // Read path (null-terminated)
        const uint8_t* path_start = ptr;
        while (ptr < end && *ptr != '\0') ptr++;
        if (ptr >= end) { truncated = true; break; }

        size_t path_len = ptr - path_start;
        ptr++;  // Skip null byte

        // Padding to 8-byte boundary (from entry_start)
        size_t entry_len = ptr - entry_start;
        size_t padding = (8 - (entry_len % 8)) % 8;
        if (ptr + padding > end) { truncated = true; break; }
        ptr += padding;

        processed++;

        // Skip entries with paths too long to store
        if (path_len >= Git::MAX_PATH_LEN) {
            LOG("git_index_open: skipping entry with path length %zu (>= MAX_PATH_LEN)", path_len);
            continue;
        }

        // Store entry
        GitIndexEntry* entry = &index->entries[index->entry_count];
        entry->mode = mode;
        entry->stage = stage;
        strcpy_s(entry->sha, sha);
        memcpy(entry->path, path_start, path_len);
        entry->path[path_len] = '\0';

        index->entry_count++;
    }

    if (truncated || processed != entry_count) {
        LOG("git_index_open: parsed %u of %u entries (truncated=%d) - index may be corrupt",
            processed, entry_count, (int)truncated);
        delete[] index->entries;
        index->entries = nullptr;
        index->entry_count = 0;
        mmap_close(mmap);
        return false;
    }

    mmap_close(mmap);
    return true;
}

// Close git index and free resources
void git_index_close(GitIndex* index) {
    if (index) {
        delete[] index->entries;
        index->entries = nullptr;
        index->entry_count = 0;
    }
}

